using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;
using ShipmentTracker.Data.Entities;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : Client.Services.IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.ShippedDate)
            .Select(s => ToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : ToDto(entity);
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var entity = await db.Shipments.FindAsync(id);
        return entity is null ? null : ToDto(entity);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var entity = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = (int)ShipmentStatus.Pending,
            ShippedDate = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            SenderName = dto.SenderName,
            WeightKg = dto.WeightKg,
            Notes = dto.Notes
        };

        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return ToDto(entity);
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");

        entity.Status = (int)status;
        if (status == ShipmentStatus.Delivered)
            entity.ActualDelivery = DateTime.UtcNow;

        await db.SaveChangesAsync();
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        SenderName = s.SenderName,
        WeightKg = s.WeightKg,
        Notes = s.Notes
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("/{id:int}", async (int id, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByIdAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).AllowAnonymous();

        group.MapPost("/", [Authorize] async ([FromBody] ShipmentDto dto, IShipmentService service) =>
        {
            var created = await service.CreateShipmentAsync(dto);
            return Results.Created($"api/shipments/{created.Id}", created);
        });

        group.MapPut("/{id:int}/status", [Authorize] async (int id, [FromBody] ShipmentStatus status, IShipmentService service) =>
        {
            await service.UpdateShipmentStatusAsync(id, status);
            return Results.NoContent();
        });
    }
}

