@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260523-12345)"
                   @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning">@errorMessage</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>Tracking #:</strong> @shipment.TrackingNumber
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @shipment.Origin</p>
                    <p><strong>To:</strong> @shipment.Destination</p>
                    <p><strong>Sender:</strong> @shipment.SenderName</p>
                    <p><strong>Recipient:</strong> @shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></p>
                    <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy HH:mm")</p>
                    }
                    <p><strong>Weight:</strong> @shipment.WeightKg.ToString("F1") kg</p>
                </div>
            </div>

            @if (!string.IsNullOrWhiteSpace(shipment.Notes))
            {
                <hr />
                <p><strong>Notes:</strong> @shipment.Notes</p>
            }

            <hr />
            <h5>Delivery Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)" role="progressbar"
                     style="width: @GetProgressPercentage(shipment.Status)%">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
            if (shipment is null)
                errorMessage = "No shipment found with that tracking number.";
        }
        catch
        {
            errorMessage = "An error occurred while searching. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercentage(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments Dashboard</PageTitle>

<h2>Shipments Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-success" @onclick="() => showCreateForm = true">+ New Shipment</button>
        <button class="btn btn-outline-primary ms-2" @onclick="LoadShipments" disabled="@isLoading">
            @if (isLoading)
            {
                <span class="spinner-border spinner-border-sm"></span>
            }
            else
            {
                <span>↻ Refresh</span>
            }
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Create New Shipment</strong>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => showCreateForm = false">✕</button>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Sender Name</label>
                    <input type="text" class="form-control" @bind="newShipment.SenderName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Name</label>
                    <input type="text" class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Weight (kg)</label>
                    <input type="number" step="0.1" class="form-control" @bind="newShipment.WeightKg" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Est. Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <label class="form-label">Notes</label>
                    <textarea class="form-control" rows="2" @bind="newShipment.Notes"></textarea>
                </div>
                <div class="col-12">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create Shipment</button>
                </div>
            </div>
        </div>
    </div>
}

@if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="table-responsive">
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Recipient</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>@shipment.RecipientName</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                        {
                            <select class="form-select form-select-sm d-inline-block" style="width: auto;"
                                    @onchange="e => UpdateStatus(shipment.Id, e)">
                                <option value="">Update...</option>
                                @foreach (var s in GetNextStatuses(shipment.Status))
                                {
                                    <option value="@((int)s)">@s</option>
                                }
                            </select>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@if (!FilteredShipments.Any() && !isLoading)
{
    <p class="text-muted text-center">No shipments found.</p>
}

@code {
    private List<ShipmentDto> shipments = [];
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool isLoading;
    private bool showCreateForm;
    private string? errorMessage;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };

    private IEnumerable<ShipmentDto> FilteredShipments => shipments
        .Where(s => string.IsNullOrEmpty(filterText) ||
                    s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
                    s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) ||
                    s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch
        {
            errorMessage = "Failed to load shipments.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task CreateShipment()
    {
        errorMessage = null;
        try
        {
            await ShipmentService.CreateShipmentAsync(newShipment);
            newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(5) };
            showCreateForm = false;
            await LoadShipments();
        }
        catch
        {
            errorMessage = "Failed to create shipment.";
        }
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (string.IsNullOrEmpty(e.Value?.ToString())) return;
        var status = (ShipmentStatus)int.Parse(e.Value.ToString()!);
        try
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, status);
            await LoadShipments();
        }
        catch
        {
            errorMessage = "Failed to update status.";
        }
    }

    private static IEnumerable<ShipmentStatus> GetNextStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Cancelled],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Cancelled],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Cancelled],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Cancelled],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

